    {
      "words": ["J'ai", "un", "chien", "."],
      "translation": "Ich habe einen Hund.",
      "explanation": "Bei A1-Sätzen steht das Subjekt (ich, tu, il etc.) meist zuerst. 'J'ai' ist die erste Person Singular von 'avoir'. Das Artikelwort 'un' passt zum maskulinen Nomen 'chien'."
    },
    {
      "words": ["Tu", "aimes", "le", "chat", "."],
      "translation": "Du magst die Katze.",
      "explanation": "Das Verb 'aimer' steht nach dem Subjekt. 'Tu' ist das Subjekt, 'aimes' der Verbenform für 'du'. Das Artikelwort 'le' passt zu 'chat', einem maskulinen Nomen."
    },
    {
      "words": ["Je", "suis", "à", "la", "maison", "."],
      "translation": "Ich bin zu Hause.",
      "explanation": "'Je suis' ist die erste Person Singular von 'être'. Der Ausdruck 'à la maison' bedeutet 'zu Hause'. Bei A1 steht der Ort nach dem Verb."
    },
    {
      "words": ["Elle", "a", "un", "chat", "."],
      "translation": "Sie hat eine Katze.",
      "explanation": "'Elle a' ist die dritte Person Singular von 'avoir'. Das Artikelwort 'un' wird verwendet, weil 'chat' maskulin ist. Die Reihenfolge ist: Subjekt - Verb - Objekt."
    },
    {
      "words": ["Nous", "aimons", "l'eau", "."],
      "translation": "Wir mögen das Wasser.",
      "explanation": "'Nous aimons' ist die erste Person Plural von 'aimer'. Das Nomen 'eau' (Wasser) ist feminin, daher verwendet man 'l'' als Artikel. Die Reihenfolge bleibt einfach: Subjekt - Verb - Objekt."
    }
  ]
}
